'use client';

import { useState } from 'react';
import { Document, Page, pdfjs } from 'react-pdf';


// Set up the worker automatically from a CDN
pdfjs.GlobalWorkerOptions.workerSrc = `//unpkg.com/pdfjs-dist@${pdfjs.version}/build/pdf.worker.min.mjs`;

import 'react-pdf/dist/Page/AnnotationLayer.css';
import 'react-pdf/dist/Page/TextLayer.css';

export default function PdfViewer({ fileUrl }) {
    const [numPages, setNumPages] = useState(null);

    function onDocumentLoadSuccess({ numPages }) {
        setNumPages(numPages);
    }

    return (
        <div className="flex flex-col items-center bg-slate-100 p-4 overflow-auto h-full">
            <Document
                file={fileUrl + '/'}
                onLoadSuccess={onDocumentLoadSuccess}
                loading={<p className="text-indigo-600">Loading PDF...</p>}
            >
                {/* This renders all pages in a list */}
                {Array.from(new Array(numPages), (el, index) => (
                    <Page
                        key={`page_${index + 1}`}
                        pageNumber={index + 1}
                        renderTextLayer={true}
                        renderAnnotationLayer={true}
                        className="mb-4 shadow-lg"
                        // Adjust width to fit your modal
                        width={window.innerWidth > 600 ? 600 : window.innerWidth - 40}
                    />
                ))}
            </Document>
        </div>
    );
}